mapper.select:
select kn.*,kc.class_name as know_class_name from knowbase_know_info kn LEFT JOIN knowbase_class_info kc on kn.know_class = kc.class_code where 1=1
and kn.know_class = #{knowbaseKnowInfo.knowClass}
and kn.know_type = #{knowbaseKnowInfo.knowType}
and (kn.know_title like concat('%',#{knowbaseKnowInfo.knowTitle},'%') or MATCH(know_content) AGAINST (#{knowbaseKnowInfo.knowTitle}))
and date_format(kn.create_time,'%Y-%m-%d') = #{knowbaseKnowInfo.queryDate}
and kn.create_user_name like concat('%',#{knowbaseKnowInfo.createUserName},'%')
and (kn.share_purv ='all' or kn.create_user_id = #{knowbaseKnowInfo.createUserId})
order by kn.create_time desc

select count(*) from knowbase_know_info kn where 1=1
AND know_class IN
#{knowClass}

